// ignore_for_file: avoid_classes_with_only_static_members

///
/// Validation
///
class RkValidate {
  ///
  /// check password if return string is has error else null not erorr
  ///
  static String? password(String password) {
    if (password.length < 8) return 'Vui lòng nhập mật khẩu tối thiểu 8 kí tự ';
    if (!password.contains(RegExp(r"[a-z]"))) return 'Các ký tự bao gồm ít nhất một chữ cái viết thường';
    if (!password.contains(RegExp(r"[A-Z]"))) return 'Các ký tự bao gồm ít nhất một chữ cái viết hoa';
    if (!password.contains(RegExp(r"[0-9]"))) return 'Các ký tự bao gồm ít nhất một chữ số';
    if (!password.contains(RegExp(r'[!@#$%^&*(),.?":{}|<>]'))) return 'Phải có ít nhất 1 kí tự đặc biệt';
    // if (password.length < 6) return 'Vui lòng nhập mật khẩu tối thiểu 6 kí tự';
    return null;
  }

  ///
  /// Validate email
  ///
  static String? email(String text) {
    // a-zA-Z0-9 : allow a - Z 0 -9
    // + @(Bắt buộc )
    final RegExp reg = RegExp(r"^[a-zA-Z0-9.a-zA-Z0-9.!#$%&'*+-/=?^_`{|}~]+@[a-zA-Z0-9]+\.[a-zA-Z]+");
    if (RkValidate.nullOrEmpty(text)) {
      return 'Địa chỉ email không được để trống';
    }
    if (!reg.hasMatch(text)) {
      // email không hợp lệ
      return "Địa chỉ email không hợp lệ";
    } else {
      // hợp lệ
      return null;
    }
  }

  ///
  /// Validate phone
  ///
  static String? phone(String text) {
    //r'^([+0]9)?[0-9]{10}$'
    final RegExp reg = RegExp(r'^([+0])\d{9}$');
    if (RkValidate.nullOrEmpty(text)) {
      return "Số điện thoại không được để trống";
    }
    if (!reg.hasMatch(text.toString()) || text.length >= 13 || text.length < 9) {
      // phone not validate
      return "Số điện thoại không hợp lệ";
    } else {
      // phone validate
      return null;
    }
  }

  ///
  /// empty
  ///
  static String? userName(String? text, {int? rangeFrom, int? rangeTo}) {
    if (RkValidate.nullOrEmpty(text)) {
      return "Tên đăng nhập không được để trống";
    }
    if (!RkValidate.nullOrEmpty(rangeFrom)) {
      if (text.toString().length < rangeFrom!) {
        return "Tên đăng nhập ít nhất phải $rangeFrom ký tự";
      }
    }
    if (!RkValidate.nullOrEmpty(rangeTo)) {
      if (text.toString().length > rangeTo!) {
        return "Tên đăng nhập không được quá $rangeTo ký tự";
      }
    }
    // if (text!.contains(RegExp(r"[0-9]"))) return 'Các ký tự không được chứa chữ số';
    if (text!.contains(RegExp(r'[ \n\t\r\f!@#$%^&*(),.?":{}|<>ÁÀẢÃẠáàảãạÂẤẦẨẪẬâấầẩẫậĂẮẰẲẴẶăắằẳẵặĐđÉÈẺẼẸéèẻẽẹÊẾỀỂỄỆêếềểễệÓÒỎÕỌóòỏõọÔỐỒỔỖỘôốồổỗộƠỚỜỞỠỢơớờởỡợÍÌỈĨỊíìỉĩịÚÙỦŨỤúùủũụƯỨỪỬỮỰưứừửữựÝỲỶỸỴýỳỷỹỵ]'))) return 'Tên đăng nhập không được có chứa ký tự đặc biệt';
    return null;
  }

  ///
  /// empty
  ///
  static String? name(String? text, {int? rangeFrom, int? rangeTo}) {
    if (RkValidate.nullOrEmpty(text)) {
      return "Họ và tên không được để trống";
    }
    if (!RkValidate.nullOrEmpty(rangeFrom)) {
      if (text.toString().length < rangeFrom!) {
        return "Họ và tên ít nhất phải $rangeFrom ký tự";
      }
    }
    if (!RkValidate.nullOrEmpty(rangeTo)) {
      if (text.toString().length > rangeTo!) {
        return "Họ và tên không được quá $rangeTo ký tự";
      }
    }
    if (text!.contains(RegExp(r"[0-9]"))) return 'Các ký tự không được chứa chữ số';
    if (text!.contains(RegExp(r'[!@#$%^&*(),.?":{}|<>]'))) return 'Họ và tên không được có chứa ký tự đặc biệt';
    return null;
  }

  ///
  /// empty
  ///
  static String? increment(String? number) {
    if (RkValidate.nullOrEmpty(number)) {
      number = '0';
    }
    if (int.parse(number!) <= 0) {
      return "Số lượng không được bé hơn 0";
    } else if (int.parse(number) >= 999) {
      return "Số lượng không được lớn hơn 999";
    }
    return null;
  }

  ///
  /// Check nullOrEmpty
  ///
  static bool nullOrEmpty(dynamic value) {
    if (value == null || value.toString().isEmpty || value.toString() == 'null' || (value is List && value.isEmpty == true)) return true;
    return false;
  }

  static String parseStringFromJson(dynamic value, {String defaultValue = ''}) {
    if (value != null && value.toString().isNotEmpty && value != 'null') {
      return value.toString();
    }

    return defaultValue;
  }

  /// check link youtube
  ///
  static const String youtubeRegex = r'^((?:https?:)?\/\/)?((?:www|m)\.)?((?:youtube(-nocookie)?\.com|youtu.be))(\/(?:[\w\-]+\?v=|embed\/|v\/)?)([\w\-]+)(\S+)?$';
  static bool validateYouTubeVideoURL({required String url}) {
    final RegExp pattern = RegExp(youtubeRegex);
    final bool match = pattern.hasMatch(url);
    return match;
  }

  static int parseIntFromJson(dynamic number, {int defaultVal = 0}) {
    if (RkValidate.nullOrEmpty(number) == false) {
      // Double
      if (number is double)
        return number.round();
      // Int
      else if (number is int)
        return number;
      else if (number is String) {
        // String double
        if (number.contains('.')) {
          return double.parse(number).round();
        } else {
          // May be string int
          return int.parse(number);
        }
      }
    }
    return defaultVal;
  }

  static int? parseIntOrNullFromJson(dynamic number, {int? defaultVal}) {
    if (RkValidate.nullOrEmpty(number) == false) {
      // Double
      if (number is double)
        return number.round();
      // Int
      else if (number is int)
        return number;
      else if (number is String) {
        // String double
        if (number.contains('.')) {
          return double.parse(number).round();
        } else {
          // May be string int
          return int.parse(number);
        }
      }
    }
    return defaultVal;
  }

  static double parseDoubleFromJson(dynamic number, {double fault = 0}) {
    if (number != null) {
      // Double
      if (number is double)
        return number;
      // Int
      else if (number is int)
        return number * 1.0;
      else if (number is String) {
        // String double
        if (number.contains('.')) {
          return double.parse(number);
        } else {
          // May be string int
          return int.parse(number) * 1.0;
        }
      }
    }
    return fault;
  }

  static double parseDoubleFromJsonPriceAtSale(dynamic number, {double fault = -1}) {
    if (number != null) {
      // Double
      if (number is double)
        return number;
      // Int
      else if (number is int)
        return number * 1.0;
      else if (number is String) {
        // String double
        if (number.contains('.')) {
          return double.parse(number);
        } else {
          // May be string int
          return int.parse(number) * 1.0;
        }
      }
    }
    return fault;
  }

  static bool parseBoolFromJson(dynamic value, {bool fault = false}) {
    if (value != null) {
      return value as bool;
    }
    return fault;
  }

  static bool parseBoolFromInt(int? value, {bool fault = false}) {
    if (value != null) {
      // ignore: avoid_bool_literals_in_conditional_expressions
      return value == 0 ? false : true;
    }
    return fault;
  }

  static String getGenderString(dynamic value) {
    if (nullOrEmpty(value) == true) return 'Không xác định';

    if (value == 1 || value == '1') {
      return "Nam";
    } else if (value == 2 || value == '2') {
      return "Nữ";
    } else if (value == 2 || value == '3') {
      return "Tất cả";
    }
    return 'Không xác định';
  }

  static String getGenderValue(dynamic value) {
    if (nullOrEmpty(value) == true) return '3';

    if (value.runtimeType == String) {
      if (value.toString().contains('Nam')) {
        return "1";
      } else if (value.toString().contains('Nữ')) {
        return "2";
      }
      return '3';
    }
    return '3';
  }

  static bool checkNetworkUrl(String url) {
    if (url.contains('http') && url.startsWith('http') || url.contains('https') && url.startsWith('https')) {
      return true;
    }
    return false;
  }
}

